// With strictNullChecks
function getLength(value: string | null): number {
  if (value === null) {
    return 0;
  }
  return value.length; // TypeScript knows value is string here
}

// With noImplicitAny
function multiply(a: number, b: number): number {
  return a * b;
}

// With noUnusedLocals
